Here is a fixed implementation of `doubleArray` you can use in `glpk.i` (`intArray` will be similar). It creates a Python object from inside the C code, so that it will get cleaned up by Python's garbage collector when the object goes out of scope. Running it on the above program, the memory leak is no longer present. It's almost as fast as the existing implementation (I suspect the slight slowdown is due to the extra work in freeing the memory).

```
PyObject* as_doubleArray(PyObject *list)
{
    /* Check if is a list */
    if (!PyList_Check(list))
    {
        PyErr_SetString(PyExc_TypeError, "not a list");
        return NULL;
    }
    
    int size = PyList_Size(list);

    PyObject *pmod   = PyImport_ImportModule("swiglpk");

    if (!pmod)
    {
        PyErr_SetString(PyExc_ImportError, "swiglpk could not be imported");
        return NULL;
    }

    PyObject *pclass = PyObject_GetAttrString(pmod, "doubleArray");
    Py_DECREF(pmod);

    if (!pclass)
    {
        PyErr_SetString(PyExc_AttributeError, "swiglpk does not contain doubleArray");
        return NULL;
    }

    // call doubleArray constructor with size + 1
    PyObject *pargs  = Py_BuildValue("(i)", size + 1);

    if (!pargs)
    {
        Py_DECREF(pclass);
        PyErr_SetString(PyExc_RuntimeError, "building arguments list for doubleArray constructor failed");
        return NULL;
    }
    
    PyObject *pinst  = PyEval_CallObject(pclass, pargs);
    Py_DECREF(pclass);
    Py_DECREF(pargs);

    if (!pinst)
    {
        PyErr_SetString(PyExc_RuntimeError, "creating doubleArray failed");
        return NULL;
    }

    PyObject* pthis = PyObject_GetAttrString(pinst, "this");

    if (!pthis)
    {
        Py_DECREF(pinst);
        PyErr_SetString(PyExc_AttributeError, "doubleArray 'this' attribute not found");
        return NULL;
    }

    // convert 'this' to a c-style pointer
    doubleArray* double_arr = 0;
    int res = SWIG_ConvertPtr(pthis, (void**)&double_arr, SWIGTYPE_p_doubleArray,  0 );
    Py_DECREF(pthis);
        
    if (!SWIG_IsOK(res))
    {
        Py_DECREF(pinst);
        PyErr_SetString(PyExc_RuntimeError, "SWIG_ConvertPtr failed");
        return NULL;
    }

    for (int i=0; i<size; i++)
    {
        PyObject *o = PyList_GetItem(list, i);
        
        if (PyFloat_Check(o))
            double_arr[i+1] = PyFloat_AsDouble(o);
        else
        {
           Py_DECREF(pinst);
           PyErr_SetString(PyExc_TypeError, "list must contain floats");
           
           return NULL;
        }
    }

    // return the doubleArray instance
    return pinst;
}
```

Thanks @bricaud :) There's actually a whole lot of libraries, see e.g. [this benchmark](https://github.com/yurymalkov/ann-benchmarks). We currently have (thanks to @naspert work):

* scipy [pdist](https://docs.scipy.org/doc/scipy/reference/generated/scipy.spatial.distance.pdist.html) (brute force), [KDTree](https://docs.scipy.org/doc/scipy-0.14.0/reference/generated/scipy.spatial.KDTree.html) and [cKDTree](https://docs.scipy.org/doc/scipy/reference/generated/scipy.spatial.cKDTree.html), because scipy is a hard requirement and will be installed for all users
* [nmslib](https://github.com/nmslib/nmslib), because it's the fastest according to the benchmark
* [flann](https://github.com/mariusmuja/flann), because it was there before and people know it

